import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { getSupabaseClient } from '@/integrations/supabase/client';
import { realtimeEventProcessor } from '@/shared/realtime/RealtimeEventProcessor';
import type { AssetRegistryEntry, ResolvedAssetRegistryEntry } from '@/tools/video-editor/types';
import type {
  TimelinePatchRegistry,
  TimelineRegisterAsset,
} from '@/tools/video-editor/hooks/timeline-state-types';

interface PrimaryVariantInfo {
  location: string;
  variant_id: string;
}

interface UseStaleVariantsArgs {
  registry: Record<string, ResolvedAssetRegistryEntry> | undefined;
  patchRegistry: TimelinePatchRegistry;
  registerAsset: TimelineRegisterAsset;
}

const POLL_INTERVAL_MS = 15_000;

/**
 * Checks which asset registry entries reference a variant that is no longer
 * the primary variant of its generation. Uses direct Supabase queries + realtime
 * subscription (no React Query) for predictable, immediate updates.
 */
export function useStaleVariants({ registry, patchRegistry, registerAsset }: UseStaleVariantsArgs) {
  const [primaryLocationMap, setPrimaryLocationMap] = useState<Record<string, PrimaryVariantInfo | null>>({});
  const [dismissedAssetKeys, setDismissedAssetKeys] = useState<Set<string>>(() => new Set());
  const fetchCounterRef = useRef(0);

  // Collect all asset keys linked to a generation
  const generationAssetMap = useMemo(() => {
    if (!registry) {
      return {
        generationIds: [] as string[],
        assetsByGeneration: {} as Record<string, { assetKey: string; file: string }[]>,
        generationAssetKeys: new Set<string>(),
      };
    }

    const assetsByGeneration: Record<string, { assetKey: string; file: string }[]> = {};
    const generationAssetKeys = new Set<string>();

    for (const [assetKey, entry] of Object.entries(registry)) {
      if (entry.generationId) {
        generationAssetKeys.add(assetKey);
        if (!assetsByGeneration[entry.generationId]) {
          assetsByGeneration[entry.generationId] = [];
        }
        assetsByGeneration[entry.generationId].push({ assetKey, file: entry.file });
      }
    }

    return {
      generationIds: Object.keys(assetsByGeneration),
      assetsByGeneration,
      generationAssetKeys,
    };
  }, [registry]);

  // Fetch primary variant locations from Supabase
  const fetchPrimaryLocations = useCallback(async (generationIds: string[]) => {
    if (generationIds.length === 0) {
      setPrimaryLocationMap({});
      return;
    }

    const fetchId = ++fetchCounterRef.current;

    const { data, error } = await getSupabaseClient()
      .from('generations')
      .select(`
        id,
        primary_variant:generation_variants!generations_primary_variant_id_fkey (
          id,
          location
        )
      `)
      .in('id', generationIds);

    if (error) {
      console.error('[StaleVariants] fetch error:', error);
      return;
    }

    // Discard if a newer fetch has started
    if (fetchId !== fetchCounterRef.current) return;

    const map: Record<string, PrimaryVariantInfo | null> = {};
    for (const row of data ?? []) {
      const pv = row.primary_variant as { id: string; location: string } | null;
      map[row.id] = pv ? { location: pv.location, variant_id: pv.id } : null;
    }

    setPrimaryLocationMap(map);
  }, []);

  // Fetch on mount, when generationIds change, and on a polling interval
  useEffect(() => {
    const { generationIds } = generationAssetMap;
    if (generationIds.length === 0) return;

    // Immediate fetch
    void fetchPrimaryLocations(generationIds);

    // Poll every 15 seconds as fallback
    const interval = setInterval(() => {
      void fetchPrimaryLocations(generationIds);
    }, POLL_INTERVAL_MS);

    return () => clearInterval(interval);
  }, [generationAssetMap, fetchPrimaryLocations]);

  // Subscribe to realtime variant/generation changes for instant updates
  useEffect(() => {
    const { generationIds } = generationAssetMap;
    if (generationIds.length === 0) return;

    const genIdSet = new Set(generationIds);

    return realtimeEventProcessor.onEvent((event) => {
      // Variant inserted/updated (e.g., new primary variant set)
      if (event.type === 'variants-changed') {
        const relevant = event.affectedGenerationIds.some((id) => genIdSet.has(id));
        if (relevant) {
          void fetchPrimaryLocations(generationIds);
        }
        return;
      }

      // Generation updated (e.g., primary_variant_id changed)
      if (event.type === 'generations-updated') {
        const relevant = event.generations.some((g) => genIdSet.has(g.id));
        if (relevant) {
          void fetchPrimaryLocations(generationIds);
        }
      }
    });
  }, [generationAssetMap, fetchPrimaryLocations]);

  // Build the set of stale asset keys (compare by file URL)
  const staleAssetKeys = useMemo(() => {
    const stale = new Set<string>();

    for (const [generationId, assets] of Object.entries(generationAssetMap.assetsByGeneration)) {
      const primaryInfo = primaryLocationMap[generationId];
      if (!primaryInfo) continue;
      for (const { assetKey, file } of assets) {
        if (file !== primaryInfo.location) {
          stale.add(assetKey);
        }
      }
    }

    return stale;
  }, [primaryLocationMap, generationAssetMap.assetsByGeneration]);

  const dismissAsset = useCallback((assetKey: string) => {
    setDismissedAssetKeys((prev) => {
      const next = new Set(prev);
      next.add(assetKey);
      return next;
    });
  }, []);

  // Update a single asset to the current primary variant
  const updateAssetToCurrentVariant = useCallback(async (assetKey: string) => {
    if (!registry) return;
    const entry = registry[assetKey];
    if (!entry?.generationId) return;

    // Fetch the current primary variant's data
    const { data, error } = await getSupabaseClient()
      .from('generations')
      .select(`
        primary_variant_id,
        primary_variant:generation_variants!generations_primary_variant_id_fkey (
          id,
          location,
          thumbnail_url
        )
      `)
      .eq('id', entry.generationId)
      .single();

    if (error || !data?.primary_variant) return;

    const newVariant = data.primary_variant as { id: string; location: string; thumbnail_url: string | null };
    const newLocation = newVariant.location;

    const updatedEntry: AssetRegistryEntry = {
      ...entry,
      file: newLocation,
      variantId: newVariant.id,
    };

    // Update in-memory registry
    patchRegistry(assetKey, updatedEntry, newLocation);

    // Persist to DB
    void registerAsset(assetKey, updatedEntry).catch((err) => {
      console.error('[StaleVariants] Failed to persist variant update:', err);
    });

    // Clear dismiss state (it's now up to date)
    setDismissedAssetKeys((prev) => {
      if (!prev.has(assetKey)) return prev;
      const next = new Set(prev);
      next.delete(assetKey);
      return next;
    });
  }, [registry, patchRegistry, registerAsset]);

  return {
    staleAssetKeys,
    dismissedAssetKeys,
    generationAssetKeys: generationAssetMap.generationAssetKeys,
    dismissAsset,
    updateAssetToCurrentVariant,
  };
}

/**
 * usePendingSegmentTasks Hook
 *
 * Tracks travel segment tasks that are "Queued" or "In Progress" for a given shot.
 * Returns a function to check if a specific pair_shot_generation_id has a pending task.
 * Supports optimistic updates for immediate UI feedback when generate is clicked.
 */

import { useMemo, useState, useEffect, useCallback } from 'react';
import { useQuery } from '@tanstack/react-query';
import { getSupabaseClient as supabase } from '@/integrations/supabase/client';
import { TASK_STATUS } from '@/types/tasks';
import { taskQueryKeys } from '@/shared/lib/queryKeys/tasks';

interface PendingSegmentTask {
  id: string;
  status: string;
  pair_shot_generation_id: string | null;
}

interface UsePendingSegmentTasksReturn {
  /** Check if a pair_shot_generation_id has a pending task (real or optimistic) */
  hasPendingTask: (pairShotGenerationId: string | null | undefined) => boolean;
  /** Get the task status for a pair_shot_generation_id */
  getTaskStatus: (pairShotGenerationId: string | null | undefined) => string | null;
  /** Set of all pair_shot_generation_ids with pending tasks */
  pendingPairIds: Set<string>;
  /** Loading state */
  isLoading: boolean;
  /** Add an optimistic pending ID (for immediate UI feedback when generate is clicked) */
  addOptimisticPending: (pairShotGenerationId: string | null | undefined) => void;
}

/**
 * Extract pair_shot_generation_id from task params
 */
function extractPairShotGenId(params: Record<string, unknown> | null): string | null {
  if (!params) return null;

  // Direct param (individual_travel_segment)
  if (params.pair_shot_generation_id) {
    return params.pair_shot_generation_id as string;
  }

  // From orchestrator_details with segment_index (travel_segment from orchestrator)
  const orchDetails = params.orchestrator_details as Record<string, unknown> | undefined;
  if (orchDetails?.pair_shot_generation_ids && typeof params.segment_index === 'number') {
    const ids = orchDetails.pair_shot_generation_ids;
    if (Array.isArray(ids) && ids[params.segment_index]) {
      return ids[params.segment_index] as string;
    }
  }

  return null;
}

export function usePendingSegmentTasks(
  shotId: string | null,
  projectId: string | null
): UsePendingSegmentTasksReturn {
  // Track optimistic pending IDs with timestamps (for immediate UI feedback before task is detected)
  // Map of pairShotGenerationId -> timestamp when added
  const [optimisticPending, setOptimisticPending] = useState<Map<string, number>>(new Map());

  // How long to wait for a task to appear in real pending before clearing optimistic
  const OPTIMISTIC_TIMEOUT_MS = 8000; // 8 seconds (covers ~2-3 query cycles)

  // Query pending segment tasks for this shot
  const { data: pendingTasks, isLoading } = useQuery({
    queryKey: [...taskQueryKeys.pendingSegment(shotId!), projectId],
    queryFn: async () => {
      if (!shotId || !projectId) return [];

      // Query tasks that are Queued or In Progress
      // Filter for travel segment task types
      const { data, error } = await supabase().from('tasks')
        .select('id, status, params')
        .eq('project_id', projectId)
        .in('status', [TASK_STATUS.QUEUED, TASK_STATUS.IN_PROGRESS])
        .in('task_type', ['travel_segment', 'individual_travel_segment']);

      if (error) {
        // Don't log here - React Query will retry automatically.
        // Errors are only surfaced via the query's error state after retries exhausted.
        throw error;
      }

      // Extract pair_shot_generation_id from each task
      const tasks: PendingSegmentTask[] = (data || []).map(task => ({
        id: task.id,
        status: task.status,
        pair_shot_generation_id: extractPairShotGenId(task.params as Record<string, unknown> | null),
      }));

      // Filter to only tasks for this shot (by checking if pair_shot_generation_id exists)
      // Note: We can't directly filter by shot_id in the query since it's in params
      // The pair_shot_generation_id links to a shot_generations record for this shot

      return tasks;
    },
    enabled: !!shotId && !!projectId,
    // Poll frequently to catch status changes
    refetchInterval: 3000,
    // Mark as stale immediately so invalidations trigger refetch
    staleTime: 0,
    // Short cache time - don't keep stale data around
    gcTime: 10000,
    // Always refetch when window regains focus
    refetchOnWindowFocus: 'always',
  });

  // Build a map of pair_shot_generation_id -> status
  const { pendingPairIds, statusMap } = useMemo(() => {
    const ids = new Set<string>();
    const map = new Map<string, string>();

    (pendingTasks || []).forEach(task => {
      if (task.pair_shot_generation_id) {
        ids.add(task.pair_shot_generation_id);
        map.set(task.pair_shot_generation_id, task.status);
      }
    });

    return { pendingPairIds: ids, statusMap: map };
  }, [pendingTasks]);

  // Clear optimistic IDs that are either:
  // 1. Confirmed (appear in real pending tasks)
  // 2. Expired (older than timeout and not in real pending - task was cancelled/failed)
  useEffect(() => {
    if (optimisticPending.size === 0 || isLoading) return;

    const now = Date.now();

    setOptimisticPending(prev => {
      const next = new Map<string, number>();
      let changed = false;

      prev.forEach((addedAt, id) => {
        const isInRealPending = pendingPairIds.has(id);
        const isExpired = now - addedAt > OPTIMISTIC_TIMEOUT_MS;

        if (isInRealPending) {
          // Confirmed by real query - clear from optimistic (real will show it)
          changed = true;
        } else if (isExpired) {
          // Not in real pending after timeout - was cancelled or failed
          changed = true;
        } else {
          // Keep it - still within timeout window
          next.set(id, addedAt);
        }
      });

      return changed ? next : prev;
    });
  }, [pendingPairIds, optimisticPending.size, isLoading, OPTIMISTIC_TIMEOUT_MS]);

  // Add an optimistic pending ID for immediate UI feedback
  const addOptimisticPending = useCallback((pairShotGenerationId: string | null | undefined) => {
    if (pairShotGenerationId) {
      setOptimisticPending(prev => new Map(prev).set(pairShotGenerationId, Date.now()));
    }
  }, []);

  // Helper to check if a pair has a pending task (real or optimistic)
  const hasPendingTask = useCallback((pairShotGenerationId: string | null | undefined): boolean => {
    if (!pairShotGenerationId) return false;
    return pendingPairIds.has(pairShotGenerationId) || optimisticPending.has(pairShotGenerationId);
  }, [pendingPairIds, optimisticPending]);

  // Helper to get task status for a pair
  const getTaskStatus = useCallback((pairShotGenerationId: string | null | undefined): string | null => {
    if (!pairShotGenerationId) return null;
    return statusMap.get(pairShotGenerationId) || null;
  }, [statusMap]);

  return {
    hasPendingTask,
    getTaskStatus,
    pendingPairIds,
    isLoading,
    addOptimisticPending,
  };
}

// NOTE: Default export removed - use named export { usePendingSegmentTasks } instead

/**
 * usePendingGenerationTasks Hook
 *
 * Tracks tasks that are "Queued" or "In Progress" that will create
 * variants or derived generations from a given source generation.
 *
 * Works for both images and videos - checks task params for source generation references.
 */

import { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { getSupabaseClient as supabase } from '@/integrations/supabase/client';
import { TASK_STATUS } from '@/types/tasks';
import { taskQueryKeys } from '@/shared/lib/queryKeys/tasks';

interface PendingGenerationTask {
  id: string;
  status: string;
  task_type: string;
}

interface UsePendingGenerationTasksReturn {
  /** Number of pending tasks that will create variants/derived from this generation */
  pendingCount: number;
  /** The pending tasks */
  pendingTasks: PendingGenerationTask[];
  /** Loading state */
  isLoading: boolean;
}

/**
 * Check if task params reference a specific generation ID as a source.
 * Checks common param fields where source generation is stored.
 */
export function taskReferencesGeneration(
  params: Record<string, unknown> | null,
  generationId: string
): boolean {
  if (!params || !generationId) return false;

  // Direct source references
  if (params.based_on === generationId) return true;
  if (params.source_generation_id === generationId) return true;
  if (params.generation_id === generationId) return true;
  if (params.input_generation_id === generationId) return true;
  if (params.parent_generation_id === generationId) return true;
  if (params.start_image_generation_id === generationId) return true;
  if (params.end_image_generation_id === generationId) return true;
  // Video segment tasks use pair_shot_generation_id
  if (params.pair_shot_generation_id === generationId) return true;
  if (Array.isArray(params.input_image_generation_ids) && params.input_image_generation_ids.includes(generationId)) {
    return true;
  }

  // Check nested in orchestrator_details
  const orchDetails = params.orchestrator_details as Record<string, unknown> | undefined;
  if (orchDetails) {
    if (orchDetails.based_on === generationId) return true;
    if (orchDetails.source_generation_id === generationId) return true;
    if (orchDetails.parent_generation_id === generationId) return true;
    if (
      Array.isArray(orchDetails.input_image_generation_ids)
      && orchDetails.input_image_generation_ids.includes(generationId)
    ) {
      return true;
    }
    // Check pair_shot_generation_ids array
    if (Array.isArray(orchDetails.pair_shot_generation_ids)) {
      if (orchDetails.pair_shot_generation_ids.includes(generationId)) return true;
    }
  }

  // Check full_orchestrator_payload
  const fullPayload = params.full_orchestrator_payload as Record<string, unknown> | undefined;
  if (fullPayload) {
    if (fullPayload.based_on === generationId) return true;
    if (fullPayload.source_generation_id === generationId) return true;
    if (fullPayload.parent_generation_id === generationId) return true;
  }

  // Check individual_segment_params (used by individual_travel_segment)
  const individualParams = params.individual_segment_params as Record<string, unknown> | undefined;
  if (individualParams) {
    if (individualParams.pair_shot_generation_id === generationId) return true;
  }

  return false;
}

export function usePendingGenerationTasks(
  generationId: string | null | undefined,
  projectId: string | null | undefined
): UsePendingGenerationTasksReturn {
  // Query pending tasks for this project
  const { data: pendingTasks, isLoading } = useQuery({
    queryKey: [...taskQueryKeys.pendingGeneration(generationId!), projectId],
    queryFn: async () => {
      if (!generationId || !projectId) return [];

      // Query tasks that are Queued or In Progress
      const { data, error } = await supabase().from('tasks')
        .select('id, status, task_type, params')
        .eq('project_id', projectId)
        .in('status', [TASK_STATUS.QUEUED, TASK_STATUS.IN_PROGRESS]);

      if (error) {
        console.error('[usePendingGenerationTasks] Query error:', error);
        return [];
      }

      // Filter to tasks that reference this generation
      const matchingTasks: PendingGenerationTask[] = (data || [])
        .filter(task => taskReferencesGeneration(task.params as Record<string, unknown> | null, generationId))
        .map(task => ({
          id: task.id,
          status: task.status,
          task_type: task.task_type,
        }));

      return matchingTasks;
    },
    enabled: !!generationId && !!projectId,
    // Poll to catch status changes
    refetchInterval: 5000,
    // Mark as stale immediately so invalidations trigger refetch
    staleTime: 0,
    // Short cache time - don't keep stale data around
    gcTime: 10000,
    // Always refetch when window regains focus
    refetchOnWindowFocus: 'always',
  });

  const result = useMemo(() => ({
    pendingCount: pendingTasks?.length || 0,
    pendingTasks: pendingTasks || [],
    isLoading,
  }), [pendingTasks, isLoading]);

  return result;
}

