import { createContext, useContext, ReactNode, useMemo } from 'react';
import { Project } from '@/types/project';
import { useRenderLogger } from '@/shared/lib/debug/debugRendering';
import { useProjectSessionCoordinator } from './useProjectSessionCoordinator';
import { requireContextValue } from './contextGuard';

// Type for updating projects (re-exported for consumers that may need it)
interface ProjectUpdate {
  name?: string;
  aspectRatio?: string;
}

interface ProjectSelectionContextType {
  selectedProjectId: string | null;
  project: Project | null;
  setSelectedProjectId: (projectId: string | null) => void;
}

interface ProjectCrudContextType {
  projects: Project[];
  isLoadingProjects: boolean;
  fetchProjects: () => Promise<void>;
  addNewProject: (projectData: { name: string; aspectRatio: string }) => Promise<Project | null>;
  isCreatingProject: boolean;
  updateProject: (projectId: string, updates: ProjectUpdate) => Promise<boolean>;
  isUpdatingProject: boolean;
  deleteProject: (projectId: string) => Promise<boolean>;
  isDeletingProject: boolean;
}

interface ProjectIdentityContextType {
  /** Current authenticated user ID, null if not logged in */
  userId: string | null;
}

interface ProjectContextType
  extends ProjectSelectionContextType,
    ProjectCrudContextType,
    ProjectIdentityContextType {}

const ProjectSelectionContext = createContext<ProjectSelectionContextType | undefined>(undefined);
const ProjectCrudContext = createContext<ProjectCrudContextType | undefined>(undefined);
const ProjectIdentityContext = createContext<ProjectIdentityContextType | undefined>(undefined);

export const ProjectProvider = ({ children }: { children: ReactNode }) => {
  const { userId, selection, crud } = useProjectSessionCoordinator();
  useRenderLogger('ProjectProvider', { userId });

  const projects = crud.projects || [];
  const selectedProjectId = selection.selectedProjectId;
  const project = projects.find((item) => item.id === selectedProjectId) ?? null;

  const selectionValue = useMemo(
    (): ProjectSelectionContextType => ({
      selectedProjectId,
      project,
      setSelectedProjectId: selection.setSelectedProjectId,
    }),
    [selectedProjectId, project, selection.setSelectedProjectId],
  );

  const crudValue = useMemo(
    (): ProjectCrudContextType => ({
      projects: crud.projects || [],
      isLoadingProjects: crud.isLoadingProjects,
      fetchProjects: crud.fetchProjects,
      addNewProject: crud.addNewProject,
      isCreatingProject: crud.isCreatingProject,
      updateProject: crud.updateProject,
      isUpdatingProject: crud.isUpdatingProject,
      deleteProject: crud.deleteProject,
      isDeletingProject: crud.isDeletingProject,
    }),
    [
      crud.projects,
      crud.isLoadingProjects,
      crud.fetchProjects,
      crud.addNewProject,
      crud.isCreatingProject,
      crud.updateProject,
      crud.isUpdatingProject,
      crud.deleteProject,
      crud.isDeletingProject,
    ],
  );

  const identityValue = useMemo(
    (): ProjectIdentityContextType => ({
      userId: userId ?? null,
    }),
    [userId],
  );

  return (
    <ProjectIdentityContext.Provider value={identityValue}>
      <ProjectCrudContext.Provider value={crudValue}>
        <ProjectSelectionContext.Provider value={selectionValue}>
          {children}
        </ProjectSelectionContext.Provider>
      </ProjectCrudContext.Provider>
    </ProjectIdentityContext.Provider>
  );
};

export const useProjectSelectionContext = () => {
  return requireContextValue(
    useContext(ProjectSelectionContext),
    'useProjectSelectionContext',
    'ProjectProvider',
  );
};

export const useProjectCrudContext = () => {
  return requireContextValue(
    useContext(ProjectCrudContext),
    'useProjectCrudContext',
    'ProjectProvider',
  );
};

export const useProjectIdentityContext = () => {
  return requireContextValue(
    useContext(ProjectIdentityContext),
    'useProjectIdentityContext',
    'ProjectProvider',
  );
};

/** Compatibility hook for existing callers that still need the combined project contract. */
export const useProject = () => {
  const selection = requireContextValue(
    useContext(ProjectSelectionContext),
    'useProject',
    'ProjectProvider',
  );
  const crud = requireContextValue(
    useContext(ProjectCrudContext),
    'useProject',
    'ProjectProvider',
  );
  const identity = requireContextValue(
    useContext(ProjectIdentityContext),
    'useProject',
    'ProjectProvider',
  );

  return useMemo<ProjectContextType>(() => ({
    ...crud,
    ...selection,
    ...identity,
  }), [crud, selection, identity]);
};

/**
 * RealtimeEventProcessor - Batches and normalizes raw database events
 *
 * Single responsibility: Take raw events, batch them within a time window,
 * and emit processed events with normalized shapes.
 *
 * Does NOT make business decisions about what to invalidate - that's the
 * React layer's job.
 */

import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import {
  RawDatabaseEvent,
  ProcessedEvent,
  ProcessedEventCallback,
  TasksUpdatedEvent,
  TasksCreatedEvent,
  GenerationsInsertedEvent,
  GenerationsUpdatedEvent,
  GenerationsDeletedEvent,
  ShotGenerationsChangedEvent,
  VariantsChangedEvent,
  VariantsDeletedEvent,
  TimelinesUpdatedEvent,
  TaskRecord,
  GenerationRecord,
  ShotGenerationRecord,
  VariantRecord,
  TimelineRecord,
  RealtimeConfig,
  DEFAULT_REALTIME_CONFIG,
} from './types';

type EventQueue = Map<string, RawDatabaseEvent[]>;

export class RealtimeEventProcessor {
  private config: RealtimeConfig;
  private queue: EventQueue = new Map();
  private batchTimeout: NodeJS.Timeout | null = null;
  private callbacks = new Set<ProcessedEventCallback>();

  constructor(config: Partial<RealtimeConfig> = {}) {
    this.config = { ...DEFAULT_REALTIME_CONFIG, ...config };
  }

  // ===========================================================================
  // Public API
  // ===========================================================================

  /**
   * Process a raw database event. Events are batched and emitted after
   * the batch window expires.
   */
  process(event: RawDatabaseEvent): void {
    const key = this.getQueueKey(event);
    const existing = this.queue.get(key) || [];
    existing.push(event);
    this.queue.set(key, existing);

    // Reset batch timer
    if (this.batchTimeout) {
      clearTimeout(this.batchTimeout);
    }

    this.batchTimeout = setTimeout(() => {
      this.flush();
    }, this.config.batchWindowMs);
  }

  /**
   * Subscribe to processed events.
   */
  onEvent(callback: ProcessedEventCallback): () => void {
    this.callbacks.add(callback);
    return () => this.callbacks.delete(callback);
  }

  /**
   * Flush any pending batched events immediately.
   */
  flush(): void {
    if (this.batchTimeout) {
      clearTimeout(this.batchTimeout);
      this.batchTimeout = null;
    }

    if (this.queue.size === 0) return;

    const now = Date.now();

    // Process each queue
    this.queue.forEach((events, key) => {
      const processed = this.processQueue(key, events, now);
      if (processed) {
        this.emit(processed);
      }
    });

    this.queue.clear();
  }

  /**
   * Clear pending events without emitting.
   */
  clear(): void {
    if (this.batchTimeout) {
      clearTimeout(this.batchTimeout);
      this.batchTimeout = null;
    }
    this.queue.clear();
  }

  /**
   * Clean up resources.
   */
  destroy(): void {
    this.clear();
    this.callbacks.clear();
  }

  // ===========================================================================
  // Private: Queue Processing
  // ===========================================================================

  private getQueueKey(event: RawDatabaseEvent): string {
    // Group by table and event type
    return `${event.table}:${event.eventType}`;
  }

  private processQueue(
    key: string,
    events: RawDatabaseEvent[],
    processedAt: number
  ): ProcessedEvent | null {
    const [table, eventType] = key.split(':') as [string, string];

    switch (table) {
      case 'tasks':
        return eventType === 'INSERT'
          ? this.processTaskInserts(events, processedAt)
          : this.processTaskUpdates(events, processedAt);

      case 'generations':
        if (eventType === 'INSERT') {
          return this.processGenerationInserts(events, processedAt);
        } else if (eventType === 'DELETE') {
          return this.processGenerationDeletes(events, processedAt);
        } else {
          return this.processGenerationUpdates(events, processedAt);
        }

      case 'shot_generations':
        return this.processShotGenerationChanges(events, processedAt);

      case 'generation_variants':
        if (eventType === 'DELETE') {
          return this.processVariantDeletes(events, processedAt);
        } else {
          return this.processVariantChanges(events, processedAt);
        }

      case 'timelines':
        return this.processTimelineUpdates(events, processedAt);

      default:
        return null;
    }
  }

  // ===========================================================================
  // Private: Task Processing
  // ===========================================================================

  private processTaskInserts(
    events: RawDatabaseEvent[],
    processedAt: number
  ): TasksCreatedEvent {
    const tasks = events.map((e) => {
      const record = e.new as unknown as TaskRecord;
      return {
        id: record.id,
        taskType: record.task_type,
        projectId: record.project_id,
      };
    });

    return {
      type: 'tasks-created',
      batchSize: events.length,
      processedAt,
      tasks,
    };
  }

  private processTaskUpdates(
    events: RawDatabaseEvent[],
    processedAt: number
  ): TasksUpdatedEvent {
    const tasks = events.map((e) => {
      const newRecord = e.new as unknown as TaskRecord;
      const oldRecord = e.old as Partial<TaskRecord> | null;

      // Extract shot ID from various possible locations
      const shotId = this.extractShotIdFromTask(newRecord);

      return {
        id: newRecord.id,
        projectId: newRecord.project_id,
        newStatus: newRecord.status,
        oldStatus: oldRecord?.status,
        isComplete: newRecord.status === 'Complete',
        isFailed: newRecord.status === 'Failed' || newRecord.status === 'Cancelled',
        shotId,
      };
    });

    return {
      type: 'tasks-updated',
      batchSize: events.length,
      processedAt,
      tasks,
    };
  }

  private extractShotIdFromTask(task: TaskRecord): string | undefined {
    // Check all possible locations for shot_id
    const metadata = task.metadata as Record<string, unknown> | undefined;
    const params = task.params as Record<string, unknown> | undefined;
    const orchestratorDetails = params?.orchestrator_details as Record<string, unknown> | undefined;
    const originalParams = params?.originalParams as Record<string, unknown> | undefined;
    const originalOrchestrator = originalParams?.orchestrator_details as Record<string, unknown> | undefined;
    const fullOrchestrator = params?.full_orchestrator_payload as Record<string, unknown> | undefined;

    const shotId =
      metadata?.shot_id ||
      metadata?.shotId ||
      params?.shot_id ||
      orchestratorDetails?.shot_id ||
      originalOrchestrator?.shot_id ||
      fullOrchestrator?.shot_id;

    return typeof shotId === 'string' ? shotId : undefined;
  }

