// Types for API responses and request bodies
// Ensure these align with your server-side definitions and Task type in @/types/tasks.ts

interface PaginatedTasksParams {
  projectId?: string | null;
  status?: TaskStatus[];
  limit?: number;
  offset?: number;
  taskType?: string | null; // Filter by specific task type
  allProjects?: boolean; // If true, query across all projects
  allProjectIds?: string[]; // List of project IDs to query when allProjects is true
}

export type PaginatedTasksResponse = RepositoryPaginatedTasksResponse;
function createPaginatedTasksQueryFn(filters: PaginatedTaskQuery, cacheProjectKey: string) {
  return async (): Promise<PaginatedTasksResponse> => {
    try {
      const result = await fetchPaginatedTasks(filters);
      notifyPaginatedTaskFetchSuccess(cacheProjectKey);
      return result;
    } catch (error) {
      notifyPaginatedTaskFetchFailure(cacheProjectKey, error);
      normalizeAndPresentAndRethrow(error, {
        context: 'useTasks.fetchPaginatedTasks',
        showToast: false,
        logData: { cacheProjectKey },
      });
    }
  };
}

// Helper to convert DB row (snake_case) to Task interface (camelCase)
// Exported for use in prefetch utilities
export { mapDbTaskToTask };

// Hook to get a single task by ID
// Uses IMMUTABLE_PRESET since task data rarely changes after creation
export const useGetTask = (taskId: string, projectId?: string | null) => {
  const effectiveProjectId = resolveTaskProjectScope(projectId);

  return useQuery<Task | null, Error>({
    queryKey: taskQueryKeys.single(taskId, effectiveProjectId),
    queryFn: async () => {
      const supabaseResult = getSupabaseClientResult();
      if (!supabaseResult.ok) {
        normalizeAndPresentAndRethrow(supabaseResult.error, {
          context: 'useTasks.useGetTask',
          showToast: false,
          logData: { taskId, projectId: effectiveProjectId },
        });
      }

      const { data, error } = await supabaseResult.client
        .from('tasks')
        .select('*')
        .eq('id', taskId)
        .eq('project_id', effectiveProjectId!)
        .maybeSingle();

      if (error) {
        normalizeAndPresentAndRethrow(error, {
          context: 'useTasks.useGetTask',
          showToast: false,
          logData: { taskId, projectId: effectiveProjectId },
        });
      }

      if (!data) {
        return null;
      }

      return mapDbTaskToTask(data);
    },
    enabled: !!taskId && !!effectiveProjectId,
    // Task data is essentially immutable once created - cache aggressively
    ...QUERY_PRESETS.immutable,
  });
};

// Hook to list tasks with pagination - GALLERY PATTERN
export const usePaginatedTasks = (params: PaginatedTasksParams) => {
  const { projectId, status, limit = 50, offset = 0, taskType, allProjects, allProjectIds } = params;
  const page = Math.floor(offset / limit) + 1;
  const effectiveProjectId: string | null = projectId ?? null;
  const cacheProjectKey = allProjects ? 'all' : effectiveProjectId;
  const safeCacheProjectKey = cacheProjectKey ?? '__no-project__';
  const visibleTaskTypes = getVisibleTaskTypes();
  const smartPollingConfig = useSmartPollingConfig(taskQueryKeys.paginated(safeCacheProjectKey));

  const query = useQuery<PaginatedTasksResponse, Error>({
    queryKey: [...taskQueryKeys.paginated(safeCacheProjectKey), page, limit, status, taskType],
    queryFn: createPaginatedTasksQueryFn({
      allProjects,
      allProjectIds,
      effectiveProjectId,
      status,
      taskType,
      visibleTaskTypes,
      limit,
      offset,
      page,
    }, safeCacheProjectKey),
    enabled: allProjects ? !!allProjectIds?.length : !!effectiveProjectId,
    placeholderData: keepPreviousData,
    ...QUERY_PRESETS.realtimeBacked,
    ...smartPollingConfig,
    refetchIntervalInBackground: true,
    retry: STANDARD_RETRY,
    retryDelay: STANDARD_RETRY_DELAY,
  });

  useProcessingRefetchGuard(status, query);

  return query;
};

/**
 * Centralized task configuration system
 * 
 * This module provides synchronous access to task type configuration.
 * Configuration is loaded from the database (task_types table) and cached globally.
 * Hardcoded fallbacks exist for backwards compatibility and offline scenarios.
 */

import { getTaskTypeConfigCache, isTaskTypeConfigCacheInitialized, type TaskTypeInfo } from '@/shared/lib/taskTypeCache';
import {
  getTaskTypeConfigFallback,
  getTaskTypeFallbackEntries,
} from '@/shared/lib/taskTypeConfigFallback';

interface TaskTypeConfig {
  /** Whether this task type should be visible in the UI */
  isVisible: boolean;
  /** Display name for the task type (overrides the raw taskType) */
  displayName?: string;
  /** Whether this task type supports progress checking */
  supportsProgress?: boolean;
  /** Whether this task type can be manually cancelled by users */
  canCancel?: boolean;
  /** Category for grouping related task types */
  category?: 'generation' | 'processing' | 'orchestration' | 'utility';
  /** Description for documentation/debugging */
  description?: string;
}

function dbConfigToTaskConfig(dbConfig: TaskTypeInfo): TaskTypeConfig {
  return {
    isVisible: dbConfig.is_visible ?? false,
    displayName: dbConfig.display_name,
    supportsProgress: dbConfig.supports_progress ?? false,
    canCancel: true, // Default all tasks to cancellable
    category: dbConfig.category as TaskTypeConfig['category'],
  };
}

/**
 * Get configuration for a specific task type
 * Checks the database cache first, falls back to hardcoded defaults
 */
function getTaskConfig(taskType: string): TaskTypeConfig {
  // Check database cache first (populated by useAllTaskTypesConfig hook)
  if (isTaskTypeConfigCacheInitialized()) {
    const cache = getTaskTypeConfigCache();
    const dbConfig = cache[taskType];
    if (dbConfig) {
      return dbConfigToTaskConfig(dbConfig);
    }
  }

  // Fall back to the shared fallback snapshot.
  const fallbackConfig = getTaskTypeConfigFallback(taskType);
  if (fallbackConfig) {
    return fallbackConfig;
  }

  // Default for completely unknown task types
  return {
    isVisible: false, // Default to hidden for unknown types
    canCancel: true,
    category: 'utility'
  };
}

function isTaskVisible(taskType: string): boolean {
  return getTaskConfig(taskType).isVisible;
}

export function getTaskDisplayName(taskType: string): string {
  const config = getTaskConfig(taskType);
  return config.displayName || taskType;
}

export function taskSupportsProgress(taskType: string): boolean {
  return getTaskConfig(taskType).supportsProgress || false;
}

/**
 * Get task types filtered by visibility
 * Uses database cache if available, falls back to hardcoded list
 */
function getTaskTypesByVisibility(visible: boolean): string[] {
  if (isTaskTypeConfigCacheInitialized()) {
    const cache = getTaskTypeConfigCache();
    return Object.entries(cache)
      .filter(([_, config]) => visible ? config.is_visible : !config.is_visible)
      .map(([taskType]) => taskType);
  }

  // Fall back to the versioned fallback snapshot.
  return getTaskTypeFallbackEntries()
    .filter(([_, config]) => visible ? config.isVisible : !config.isVisible)
    .map(([taskType]) => taskType);
}

export function getVisibleTaskTypes(): string[] {
  return getTaskTypesByVisibility(true);
}

export function getHiddenTaskTypes(): string[] {
  return getTaskTypesByVisibility(false);
}

export function filterVisibleTasks<T extends { taskType: string }>(tasks: T[]): T[] {
  return tasks.filter(task => isTaskVisible(task.taskType));
}

