    setIsCreatingLocal(false);
    if (shot) {
      setCreatedShot(shot);
    }
  }, [props.onCreateShotFromSelection]);

  const pos = adjusted ?? props.contextMenu;
  const visibleExistingShots = (props.existingShots ?? []).filter((shot) => shot.id !== createdShot?.id);
  const hasLowerShotActions = Boolean(
    (!createdShot && (props.onCreateShotFromSelection || props.onGenerateVideoFromSelection))
    || (createdShot && (props.onNavigateToShot || props.onOpenGenerateVideo)),
  );

  return createPortal(
    <div
      ref={props.menuRef}
      className="fixed z-50 min-w-[10rem] overflow-hidden rounded-md border bg-popover p-1 text-popover-foreground shadow-md animate-in fade-in-0 zoom-in-95"
      style={{ left: pos.x, top: pos.y }}
    >
      {!props.hasBatchSelection && props.isGenerationAsset && props.onUpdateVariant && (
        <ClipContextMenuItem icon={RefreshCw} onClick={() => { props.onUpdateVariant?.(); props.closeMenu(); }}>
          Update to current variant
        </ClipContextMenuItem>
      )}
      {!props.hasBatchSelection && props.isVariantStale && props.onDismissStale && (
        <ClipContextMenuItem icon={X} onClick={() => { props.onDismissStale?.(); props.closeMenu(); }}>
          Dismiss reminder
        </ClipContextMenuItem>
      )}
      {((props.isGenerationAsset && props.onUpdateVariant) || (props.isVariantStale && props.onDismissStale)) && !props.hasBatchSelection && (
        <div className="my-1 h-px bg-border" />
      )}
      {!props.hasBatchSelection && props.onSplitHere && (
        <ClipContextMenuItem icon={Scissors} onClick={() => { props.onSplitHere?.(props.actionId, props.contextMenu.clientX); props.closeMenu(); }}>
          Split Here
        </ClipContextMenuItem>
      )}
      {props.hasBatchSelection && props.onToggleMuteClips && (
        <ClipContextMenuItem icon={Music2} onClick={() => { props.onToggleMuteClips?.(props.selectedClipIds); props.closeMenu(); }}>
          Mute/Unmute {props.selectedClipIds.length} clips
        </ClipContextMenuItem>
      )}
      {props.hasBatchSelection && props.onSplitClipsAtPlayhead && (
        <ClipContextMenuItem icon={Scissors} onClick={() => { props.onSplitClipsAtPlayhead?.(props.selectedClipIds); props.closeMenu(); }}>
          Split {props.selectedClipIds.length} clips at playhead
        </ClipContextMenuItem>
      )}
      {props.showShotActions && props.hasActionsBeforeShotSection && <div className="my-1 h-px bg-border" />}
      {props.showShotActions && visibleExistingShots.map((shot) => (
        <div key={shot.id} className="flex w-full items-center gap-1 rounded-sm px-2 py-1.5 text-sm">
          <span className="min-w-0 flex-1 truncate">{shot.name}</span>
          {props.onOpenGenerateVideo && (
            <button type="button" className="flex h-5 w-5 shrink-0 items-center justify-center rounded hover:bg-accent hover:text-accent-foreground" onClick={() => { props.onOpenGenerateVideo?.(shot); props.closeMenu(); }} title="Generate Video">
              <Clapperboard className="h-3.5 w-3.5" />
            </button>
          )}
          {props.onNavigateToShot && (
            <button type="button" className="flex h-5 w-5 shrink-0 items-center justify-center rounded hover:bg-accent hover:text-accent-foreground" onClick={() => { props.onNavigateToShot?.(shot); props.closeMenu(); }} title="Jump to shot">
              <ArrowRight className="h-3.5 w-3.5" />
            </button>
          )}
        </div>
      ))}
      {props.showShotActions && visibleExistingShots.length > 0 && hasLowerShotActions && (
        <div className="my-1 h-px bg-border" />
      )}
      {props.showShotActions && !createdShot && props.onCreateShotFromSelection && (
        <ClipContextMenuItem icon={FolderPlus} onClick={() => void handleCreateShot()} disabled={isCreatingLocal || props.isCreatingShot}>
          {isCreatingLocal ? 'Creating…' : 'Create Shot'}
        </ClipContextMenuItem>
      )}
      {props.showShotActions && createdShot && props.onNavigateToShot && (
        <ClipContextMenuItem icon={ArrowRight} onClick={() => { props.onNavigateToShot?.(createdShot); props.closeMenu(); }}>
          Jump to {createdShot.name}
        </ClipContextMenuItem>
      )}
      {props.showShotActions && createdShot && props.onOpenGenerateVideo && (
        <ClipContextMenuItem icon={Clapperboard} onClick={() => { props.onOpenGenerateVideo?.(createdShot); props.closeMenu(); }}>
          Generate Video
        </ClipContextMenuItem>
      )}
      {props.showShotActions && !createdShot && props.onGenerateVideoFromSelection && (
        <ClipContextMenuItem icon={Clapperboard} onClick={() => { props.closeMenu(); void props.onGenerateVideoFromSelection?.(); }} disabled={props.isCreatingShot}>
          Generate Video
        </ClipContextMenuItem>
      )}
      {props.hasBatchSelection && props.onDeleteClips ? (
        <ClipContextMenuItem
          icon={Trash2}
          onClick={() => { props.onDeleteClips?.(props.selectedClipIds); props.closeMenu(); }}
          destructive
          suffix={<span className="ml-auto text-xs tracking-widest opacity-60">Del</span>}
        >
          Delete {props.selectedClipIds.length} clips
        </ClipContextMenuItem>
      ) : props.onDeleteClip && (
        <ClipContextMenuItem
          icon={Trash2}
          onClick={() => { props.onDeleteClip?.(props.actionId); props.closeMenu(); }}
          destructive
          suffix={<span className="ml-auto text-xs tracking-widest opacity-60">Del</span>}
        >
          Delete Clip
        </ClipContextMenuItem>
      )}
    </div>,
    document.body,
  );
}

function ClipActionComponent({
  action,
  clipMeta,
  isSelected,
  isPrimary = false,
  selectedClipIds = [],
  thumbnailSrc,
  onSelect,
  onDoubleClickAsset,
  onSplitHere,
  onSplitClipsAtPlayhead,
  onDeleteClip,
  onDeleteClips,
  onToggleMuteClips,
  isVariantStale,
  isGenerationAsset,
  onUpdateVariant,
  onDismissStale,
  canCreateShotFromSelection = false,
  existingShots,
  onCreateShotFromSelection,
  onGenerateVideoFromSelection,
  onNavigateToShot,
  onOpenGenerateVideo,
  isCreatingShot = false,
  audioSrc,
  clipWidth,
}: ClipActionProps) {
  const [contextMenu, setContextMenu] = useState<ContextMenuState | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);
  const openMenuWithSelectionRef = useRef<(clientX: number, clientY: number) => void>(() => undefined);
  const { waveform } = useWaveformData(audioSrc, {
    from: clipMeta.from,
    to: clipMeta.to,
    speed: clipMeta.speed,
    numBuckets: Math.max(2, Math.floor((clipWidth ?? 60) / 3)),
  });

  const closeMenu = useCallback(() => setContextMenu(null), []);
  const openMenuAt = useCallback((x: number, y: number) => { setContextMenu({ x, y, clientX: x }); }, []);

  useEffect(() => {
    if (!contextMenu) return;
    const handleClickOutside = (e: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        closeMenu();
      }
    };
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === 'Escape') closeMenu();
    };
    document.addEventListener('mousedown', handleClickOutside);
    document.addEventListener('keydown', handleEscape);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
      document.removeEventListener('keydown', handleEscape);
    };

    };
  }, [contextMenu, closeMenu]);

  openMenuWithSelectionRef.current = (clientX: number, clientY: number) => {
    if (!isSelected) {
      onSelect(action.id, clipMeta.track);
      requestAnimationFrame(() => openMenuAt(clientX, clientY));
      return;
    }

    openMenuAt(clientX, clientY);
  };

  const handleContextMenu = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    const { clientX, clientY } = e;
    openMenuWithSelectionRef.current(clientX, clientY);
  }, []);
  const isEffectLayer = clipMeta.clipType === 'effect-layer';
  const icon = isEffectLayer
    ? <Layers className="h-3 w-3" />
    : clipMeta.clipType === 'text'
    ? <Type className="h-3 w-3" />
    : clipMeta.track.startsWith('A')
      ? <Music2 className="h-3 w-3" />
      : <ImageIcon className="h-3 w-3" />;
  const hasBatchSelection = isSelected && selectedClipIds.length > 1;
  const showShotActions = canCreateShotFromSelection && (
    typeof onCreateShotFromSelection === 'function' || typeof onGenerateVideoFromSelection === 'function'
  );
  const hasActionsBeforeShotSection = (
    (!hasBatchSelection && isGenerationAsset && onUpdateVariant)
    || (!hasBatchSelection && isVariantStale && onDismissStale)
    || (!hasBatchSelection && onSplitHere)
    || (hasBatchSelection && onToggleMuteClips)
    || (hasBatchSelection && onSplitClipsAtPlayhead)
  );
  const effectBadges = [clipMeta.entrance?.type ? `In:${clipMeta.entrance.type}` : null, clipMeta.continuous?.type ? `Loop:${clipMeta.continuous.type}` : null, clipMeta.exit?.type ? `Out:${clipMeta.exit.type}` : null].filter(Boolean);

  return (
    <>
      <button
        type="button"
        className={cn(
          'clip-action group relative flex h-full w-full overflow-hidden rounded-md border text-left',
          isEffectLayer && isSelected
            ? 'border-violet-400 bg-violet-500/20 text-violet-50'
            : isEffectLayer
              ? 'border-violet-500/30 bg-violet-500/10 text-violet-300 hover:border-violet-400/60'
            : isSelected
            ? 'border-sky-400 bg-sky-500/20 text-sky-50'
            : 'border-border bg-card/90 text-foreground hover:border-accent',
        )}
        data-clip-id={action.id}
        data-row-id={clipMeta.track}
        onPointerDown={(event) => event.stopPropagation()}
        onDoubleClick={(event) => {
          event.stopPropagation();
          if (!isEffectLayer && clipMeta.clipType !== 'text' && clipMeta.asset) {
            onDoubleClickAsset?.(clipMeta.asset);
          }
        }}
        onContextMenu={handleContextMenu}
      >
        {waveform ? <WaveformOverlay waveform={waveform} /> : null}
        {thumbnailSrc ? (
          <img src={thumbnailSrc} alt="" className="relative z-10 h-full w-10 shrink-0 object-cover opacity-80" draggable={false} />
        ) : (
          <div className="relative z-10 flex h-full w-8 shrink-0 items-center justify-center bg-background/60 text-muted-foreground">
            {icon}
          </div>
        )}
        <div className="relative z-10 min-w-0 flex-1 px-2 py-1">
          <div className="truncate text-[11px] font-medium">
            {isEffectLayer
              ? (clipMeta.continuous?.type || 'Effect Layer')
              : (clipMeta.text?.content || clipMeta.asset || action.id)}
          </div>
          {effectBadges.length > 0 && (
            <div className="mt-1 flex gap-1 overflow-hidden">
              {effectBadges.slice(0, 2).map((badge) => (
                <span key={badge} className="truncate rounded bg-background/60 px-1 py-0.5 text-[9px] uppercase tracking-[0.12em] text-muted-foreground">
                  {badge}
                </span>
              ))}
            </div>
          )}
        </div>
        {isVariantStale && (
          <div
            className="absolute right-1 top-1 z-20 flex h-4 w-4 cursor-pointer items-center justify-center rounded-full bg-amber-500 text-white hover:bg-amber-400"
            title="Variant outdated"
            role="button"
            onClick={(e) => {
              e.stopPropagation();
              const { clientX, clientY } = e;
              openMenuWithSelectionRef.current(clientX, clientY);
            }}
          >
            <RefreshCw className="h-2.5 w-2.5" />
          </div>
        )}
      </button>

      {contextMenu && (
        <ClipContextMenu
          actionId={action.id}
          contextMenu={contextMenu}
          menuRef={menuRef}
          closeMenu={closeMenu}
          hasBatchSelection={hasBatchSelection}
          selectedClipIds={selectedClipIds}
          isGenerationAsset={isGenerationAsset}
          onUpdateVariant={onUpdateVariant}
          isVariantStale={isVariantStale}
          onDismissStale={onDismissStale}
          onSplitHere={onSplitHere}
          onToggleMuteClips={onToggleMuteClips}
          onSplitClipsAtPlayhead={onSplitClipsAtPlayhead}
          showShotActions={showShotActions}
          hasActionsBeforeShotSection={hasActionsBeforeShotSection}
          existingShots={existingShots}
          onCreateShotFromSelection={onCreateShotFromSelection}
          onGenerateVideoFromSelection={onGenerateVideoFromSelection}
          onNavigateToShot={onNavigateToShot}
          onOpenGenerateVideo={onOpenGenerateVideo}
          isCreatingShot={isCreatingShot}
          onDeleteClip={onDeleteClip}
          onDeleteClips={onDeleteClips}
        />
      )}
    </>
  );
}

function areClipActionPropsEqual(prev: ClipActionProps, next: ClipActionProps): boolean {
  if (prev.action !== next.action) return false;
  if (prev.clipMeta !== next.clipMeta) return false;
  if (prev.isSelected !== next.isSelected) return false;
  if (prev.isPrimary !== next.isPrimary) return false;
  if (prev.thumbnailSrc !== next.thumbnailSrc) return false;
  if (prev.audioSrc !== next.audioSrc) return false;
  if (prev.clipWidth !== next.clipWidth) return false;
  if (prev.isVariantStale !== next.isVariantStale) return false;
  if (prev.isGenerationAsset !== next.isGenerationAsset) return false;
  if (prev.canCreateShotFromSelection !== next.canCreateShotFromSelection) return false;
  if (prev.isCreatingShot !== next.isCreatingShot) return false;
  if (prev.selectedClipIds.length !== next.selectedClipIds.length) return false;
  if ((prev.existingShots?.length ?? 0) !== (next.existingShots?.length ?? 0)) return false;

  for (let index = 0; index < prev.selectedClipIds.length; index += 1) {
    if (prev.selectedClipIds[index] !== next.selectedClipIds[index]) {
      return false;
    }
  }

  const previousShots = prev.existingShots ?? [];
  const nextShots = next.existingShots ?? [];
  for (let index = 0; index < previousShots.length; index += 1) {
    if (previousShots[index]?.id !== nextShots[index]?.id) {
      return false;
    }
  }

  return (
    prev.onSelect === next.onSelect
    && prev.onDoubleClickAsset === next.onDoubleClickAsset
    && prev.onSplitHere === next.onSplitHere
    && prev.onSplitClipsAtPlayhead === next.onSplitClipsAtPlayhead
    && prev.onDeleteClip === next.onDeleteClip
    && prev.onDeleteClips === next.onDeleteClips
    && prev.onToggleMuteClips === next.onToggleMuteClips
    && prev.onCreateShotFromSelection === next.onCreateShotFromSelection
    && prev.onGenerateVideoFromSelection === next.onGenerateVideoFromSelection
    && prev.onNavigateToShot === next.onNavigateToShot
    && prev.onOpenGenerateVideo === next.onOpenGenerateVideo
  );
}

export const ClipAction = React.memo(ClipActionComponent, areClipActionPropsEqual);
ClipAction.displayName = 'ClipAction';

const handleClipSelect = useCallback((clipId: string, trackId: string) => {
  selectClip(clipId);
  setSelectedTrackId(trackId);
}, [selectClip, setSelectedTrackId]);

const pixelsPerSecond = scaleWidth / scale;
const finalVideoShotIds = useMemo(() => {
  const shotIds = new Set<string>();
  for (const shotId of finalVideoMap.keys()) {
    if (!dismissedShotIds.has(shotId)) {
      shotIds.add(shotId);
    }
  }
  return shotIds;
}, [dismissedShotIds, finalVideoMap]);
const shotGroups = useShotGroups(
  data?.rows ?? [],
  data?.meta ?? EMPTY_CLIP_META,
  data?.registry ?? EMPTY_ASSET_REGISTRY,
  shots,
  finalVideoShotIds,
);
const assetGenerationMap = useMemo<Record<string, string>>(() => {
  const assets = data?.registry?.assets;
  if (!assets) {
    return EMPTY_ASSET_GENERATION_MAP;
  }

  return Object.entries(assets).reduce<Record<string, string>>((acc, [assetKey, assetEntry]) => {
    if (typeof assetEntry?.generationId === 'string' && assetEntry.generationId.length > 0) {
      acc[assetKey] = assetEntry.generationId;
    }
    return acc;
  }, {});
}, [data?.registry?.assets]);
const stableAssetGenerationMap = useStableValue(assetGenerationMap);
const resolvedClipMap = useMemo(() => {
  if (!resolvedConfig) {
    return new Map<string, ResolvedTimelineClip>();
  }

  return new Map(resolvedConfig.clips.map((clip) => [clip.id, clip]));
}, [resolvedConfig]);
const trackMap = useMemo(() => {
  if (!resolvedConfig) {
    return new Map<string, TrackDefinition>();
  }

  return new Map(resolvedConfig.tracks.map((track) => [track.id, track]));
}, [resolvedConfig]);

const selectionShotCreationState = useMemo(() => {
  if (!data?.rows || !data?.meta) {
    return { canCreateShot: false, generationIds: [] as string[] };
  }

  return resolveSelectedGenerationIdsForShotCreation({
    rows: data.rows,
    meta: data.meta,
    assetGenerationMap: stableAssetGenerationMap,
    selectedClipIds,
  });
}, [data?.rows, data?.meta, stableAssetGenerationMap, selectedClipIds]);

const existingShotsForSelection = useMemo(() => {
  if (selectionShotCreationState.generationIds.length === 0 || !shots?.length) {
    return [] as Shot[];
  }

  return shots.filter((shot) => {
    const shotGenerationIds = new Set(
      (shot.images ?? [])
        .map((image) => image.generation_id)
        .filter((generationId): generationId is string => typeof generationId === 'string' && generationId.length > 0),
    );

    return selectionShotCreationState.generationIds.every((generationId) => shotGenerationIds.has(generationId));
  });
}, [shots, selectionShotCreationState.generationIds]);

const handleCreateShotFromSelection = useCallback(async (): Promise<Shot | null> => {
  if (!selectionShotCreationState.canCreateShot) {
    return null;
  }

  const result = await createShot({ generationIds: selectionShotCreationState.generationIds });
  if (result?.shot) {
    return result.shot;
  }
  return null;
}, [createShot, selectionShotCreationState]);

const handleGenerateVideoFromSelection = useCallback(async () => {
  if (!selectionShotCreationState.canCreateShot) {
    return;
  }

  const result = await createShot({ generationIds: selectionShotCreationState.generationIds });
  if (!result?.shotId) {
    return;
  }

  const createdShot = result.shot ?? shots?.find((shot) => shot.id === result.shotId) ?? null;
  if (createdShot) {
    setVideoModalShot(createdShot);
  }
}, [createShot, selectionShotCreationState, shots]);

const handleNavigateToShot = useCallback((shot: Shot) => {
  navigateToShot(shot, { isNewlyCreated: true });
}, [navigateToShot]);

const handleOpenGenerateVideo = useCallback((shot: Shot) => {
  setVideoModalShot(shot);
}, []);

const handleShotGroupNavigate = useCallback((shotId: string) => {
  const shot = shots?.find((s) => s.id === shotId);
  if (shot) navigateToShot(shot, { isNewlyCreated: false });
}, [navigateToShot, shots]);

const handleShotGroupGenerateVideo = useCallback((shotId: string) => {
  const shot = shots?.find((s) => s.id === shotId);
  if (shot) setVideoModalShot(shot);
}, [shots]);
const handleSwitchToFinalVideo = useSwitchToFinalVideo({
  applyEdit,
  dataRef,
  finalVideoMap,
  patchRegistry,
  registerAsset,
});

const clientXToTime = useCallback((clientX: number): number => {
  const wrapper = timelineWrapperRef.current;
  if (!wrapper) return 0;
  const editArea = wrapper.querySelector<HTMLElement>('.timeline-canvas-edit-area');
  const grid = editArea;
  const rect = (editArea ?? wrapper).getBoundingClientRect();
  const scrollLeft = grid?.scrollLeft ?? 0;
  return Math.max(0, (clientX - rect.left + scrollLeft - TIMELINE_START_LEFT) / pixelsPerSecond);
}, [pixelsPerSecond, timelineWrapperRef]);

const handleSplitClipHere = useCallback((clipId: string, clientX: number) => {
  const time = clientXToTime(clientX);
  handleSplitClipAtTime(clipId, time);
}, [clientXToTime, handleSplitClipAtTime]);

const getActionRender = useCallback((action: TimelineAction, _row: TimelineRow, clipWidth: number) => {
  const clipMeta = data?.meta[action.id];
  if (!clipMeta) {
    return null;
  }

  const resolvedClip = resolvedClipMap.get(action.id);
  const track = resolvedClip ? trackMap.get(resolvedClip.track) : undefined;
  const clipWidthPx = clipWidth;
  const thumbnailSrc = clipWidthPx >= 40 ? thumbnailMap[action.id] : undefined;
  const assetKey = clipMeta.asset;
  const audioSrc = resolveWaveformAudioSrc(resolvedClip, track);
  const isStale = assetKey ? staleAssetKeys.has(assetKey) : false;
  const isDismissed = assetKey ? dismissedAssetKeys.has(assetKey) : false;
  const isGenAsset = assetKey ? generationAssetKeys.has(assetKey) : false;

  return (
    <ClipAction
      action={action}
      clipMeta={clipMeta}
      isSelected={isClipSelected(action.id)}
      isPrimary={primaryClipId === action.id}
      selectedClipIds={[...selectedClipIds]}
      thumbnailSrc={thumbnailSrc}
      audioSrc={audioSrc}
      clipWidth={clipWidthPx}
      onSelect={handleClipSelect}
      onDoubleClickAsset={onDoubleClickAsset}
      onSplitHere={handleSplitClipHere}
      onSplitClipsAtPlayhead={handleSplitClipsAtPlayhead}
      onDeleteClips={handleDeleteClips}
      onDeleteClip={handleDeleteClip}
      onToggleMuteClips={handleToggleMuteClips}
      isVariantStale={isStale && !isDismissed}
      isGenerationAsset={isGenAsset}
      onUpdateVariant={isGenAsset && assetKey ? () => void updateAssetToCurrentVariant(assetKey) : undefined}
      onDismissStale={isStale && assetKey ? () => dismissAsset(assetKey) : undefined}
      canCreateShotFromSelection={selectionShotCreationState.canCreateShot}
      existingShots={existingShotsForSelection}
      onCreateShotFromSelection={handleCreateShotFromSelection}
      onGenerateVideoFromSelection={handleGenerateVideoFromSelection}
      onNavigateToShot={handleNavigateToShot}
      onOpenGenerateVideo={handleOpenGenerateVideo}
      isCreatingShot={isCreating}
    />
  );
}, [
  selectionShotCreationState.canCreateShot,
  existingShotsForSelection,
  data,
  dismissAsset,
  dismissedAssetKeys,
  generationAssetKeys,
  handleCreateShotFromSelection,
  handleClipSelect,
  handleDeleteClip,
  handleDeleteClips,
  handleGenerateVideoFromSelection,
  handleNavigateToShot,
  handleOpenGenerateVideo,
  handleSplitClipHere,
  handleSplitClipsAtPlayhead,
  handleToggleMuteClips,
  isCreating,
  isClipSelected,
  onDoubleClickAsset,
  primaryClipId,
  resolvedClipMap,
  trackMap,
  selectedClipIds,
  staleAssetKeys,
  thumbnailMap,
  updateAssetToCurrentVariant,
]);

const handleTrackDragEnd = useCallback(({ active, over }: DragEndEvent) => {
  if (!over) {
    return;
  }

  const activeSortableId = String(active.id);
  const overSortableId = String(over.id);
  if (
    activeSortableId === overSortableId ||
    !activeSortableId.startsWith('track-') ||
    !overSortableId.startsWith('track-')
  ) {
    return;
  }

  const activeTrackId = activeSortableId.slice('track-'.length);
  const overTrackId = overSortableId.slice('track-'.length);
  handleMoveTrack(activeTrackId, overTrackId);
}, [handleMoveTrack]);

if (!data) {
  return null;
}

return (
  <div className="flex h-full overflow-hidden rounded-xl border border-border bg-card/80">
    <div
      ref={timelineWrapperRef as React.RefObject<HTMLDivElement>}
      className="timeline-wrapper relative min-w-0 flex-1 overflow-hidden"
      onDragOver={onTimelineDragOver}
      onDragLeave={onTimelineDragLeave}
      onDrop={onTimelineDrop}
    >
      <TimelineCanvas
        ref={timelineRef as React.RefObject<import('@/tools/video-editor/types/timeline-canvas').TimelineCanvasHandle>}
        rows={data.rows}
        tracks={data.tracks}
        scale={scale}
        scaleWidth={scaleWidth}
        scaleSplitCount={5}
        startLeft={TIMELINE_START_LEFT}
        rowHeight={ROW_HEIGHT}
        minScaleCount={scaleCount}
        maxScaleCount={scaleCount}
        selectedTrackId={selectedTrackId}
        getActionRender={getActionRender}
        onSelectTrack={setSelectedTrackId}
        onTrackChange={handleTrackPopoverChange}
        onRemoveTrack={handleRemoveTrack}
        onTrackDragEnd={handleTrackDragEnd}
        trackSensors={trackSensors}
        onCursorDrag={onCursorDrag}
        onClickTimeArea={onClickTimeArea}
        onActionResizeStart={onActionResizeStart}
        onActionResizeEnd={onActionResizeEnd}
        shotGroups={shotGroups}
        finalVideoShotIds={finalVideoShotIds}
        onShotGroupNavigate={handleShotGroupNavigate}
        onShotGroupGenerateVideo={handleShotGroupGenerateVideo}
        onShotGroupSwitchToFinalVideo={(group) => { dismissShot(group.shotId); handleSwitchToFinalVideo(group); }}
        onShotGroupDismissFinalVideo={dismissShot}
        onSelectClips={selectClips}
        dragSessionRef={dragSessionRef}
        marqueeRect={marqueeRect}
        onEditAreaPointerDown={onMarqueePointerDown}
        onAddTrack={chrome.handleAddTrack}
        onAddTextAt={chrome.handleAddTextAt}
        unusedTrackCount={chrome.unusedTrackCount}
        onClearUnusedTracks={chrome.handleClearUnusedTracks}
        newTrackDropLabel={newTrackDropLabel}
      />
      <DropIndicator ref={indicatorRef} editAreaRef={editAreaRef} onNewTrackLabel={setNewTrackDropLabel} />
    </div>

    {videoModalShot && (
