406	function areClipActionPropsEqual(prev: ClipActionProps, next: ClipActionProps): boolean {
407	  if (prev.action !== next.action) return false;
408	  if (prev.clipMeta !== next.clipMeta) return false;
409	  if (prev.isSelected !== next.isSelected) return false;
410	  if (prev.isPrimary !== next.isPrimary) return false;
411	  if (prev.thumbnailSrc !== next.thumbnailSrc) return false;
412	  if (prev.audioSrc !== next.audioSrc) return false;
413	  if (prev.clipWidth !== next.clipWidth) return false;
414	  if (prev.isTaskActive !== next.isTaskActive) return false;
415	  if (prev.isVariantStale !== next.isVariantStale) return false;
416	  if (prev.isGenerationAsset !== next.isGenerationAsset) return false;
417	  if (prev.canCreateShotFromSelection !== next.canCreateShotFromSelection) return false;
418	  if (prev.isCreatingShot !== next.isCreatingShot) return false;
419	  if (prev.selectedClipIds.length !== next.selectedClipIds.length) return false;
420	  if ((prev.existingShots?.length ?? 0) !== (next.existingShots?.length ?? 0)) return false;
421	
422	  for (let index = 0; index < prev.selectedClipIds.length; index += 1) {
423	    if (prev.selectedClipIds[index] !== next.selectedClipIds[index]) {
424	      return false;
425	    }
426	  }
427	
428	  const previousShots = prev.existingShots ?? [];
429	  const nextShots = next.existingShots ?? [];
430	  for (let index = 0; index < previousShots.length; index += 1) {
431	    if (previousShots[index]?.id !== nextShots[index]?.id) {
432	      return false;
433	    }
434	  }
435	
436	  return (
437	    prev.onSelect === next.onSelect
438	    && prev.onDoubleClickAsset === next.onDoubleClickAsset
439	    && prev.onSplitHere === next.onSplitHere
440	    && prev.onSplitClipsAtPlayhead === next.onSplitClipsAtPlayhead
441	    && prev.onDeleteClip === next.onDeleteClip
442	    && prev.onDeleteClips === next.onDeleteClips
443	    && prev.onToggleMuteClips === next.onToggleMuteClips
444	    && prev.onCreateShotFromSelection === next.onCreateShotFromSelection
445	    && prev.onGenerateVideoFromSelection === next.onGenerateVideoFromSelection
446	    && prev.onNavigateToShot === next.onNavigateToShot
447	    && prev.onOpenGenerateVideo === next.onOpenGenerateVideo
448	  );
449	}
450	
451	export const ClipAction = React.memo(ClipActionComponent, areClipActionPropsEqual);
452	ClipAction.displayName = 'ClipAction';

