  2	 * usePendingGenerationTasks Hook
  3	 *
  4	 * Tracks tasks that are "Queued" or "In Progress" that will create
  5	 * variants or derived generations from a given source generation.
  6	 *
  7	 * Works for both images and videos - checks task params for source generation references.
  8	 */
  9	
 10	import { useMemo } from 'react';
 11	import { useQuery } from '@tanstack/react-query';
 12	import { TASK_STATUS } from '@/types/tasks';
 13	import { taskQueryKeys } from '@/shared/lib/queryKeys/tasks';
 14	
 15	interface PendingGenerationTask {
 16	  id: string;
 17	  status: string;
 18	  task_type: string;
 19	}
 20	
 21	interface UsePendingGenerationTasksReturn {
 22	  /** Number of pending tasks that will create variants/derived from this generation */
 23	  pendingCount: number;
 24	  /** The pending tasks */
 25	  pendingTasks: PendingGenerationTask[];
 26	  /** Loading state */
 27	  isLoading: boolean;
 28	}
 29	
 30	/**
 31	 * Check if task params reference a specific generation ID as a source.
 32	 * Checks common param fields where source generation is stored.
 33	 */
 34	export function taskReferencesGeneration(
 35	  params: Record<string, unknown> | null,
 36	  generationId: string
 37	): boolean {
 38	  if (!params || !generationId) return false;
 39	
 40	  // Direct source references
 41	  if (params.based_on === generationId) return true;
 42	  if (params.source_generation_id === generationId) return true;
 43	  if (params.generation_id === generationId) return true;
 44	  if (params.input_generation_id === generationId) return true;
 45	  if (params.parent_generation_id === generationId) return true;
 46	  if (params.start_image_generation_id === generationId) return true;
 47	  if (params.end_image_generation_id === generationId) return true;
 48	  // Video segment tasks use pair_shot_generation_id
 49	  if (params.pair_shot_generation_id === generationId) return true;
 50	  if (Array.isArray(params.input_image_generation_ids) && params.input_image_generation_ids.includes(generationId)) {
 51	    return true;
 52	  }
 53	
 54	  // Check nested in orchestrator_details
 55	  const orchDetails = params.orchestrator_details as Record<string, unknown> | undefined;
 56	  if (orchDetails) {
 57	    if (orchDetails.based_on === generationId) return true;
 58	    if (orchDetails.source_generation_id === generationId) return true;
 59	    if (orchDetails.parent_generation_id === generationId) return true;
 60	    if (
 61	      Array.isArray(orchDetails.input_image_generation_ids)
 62	      && orchDetails.input_image_generation_ids.includes(generationId)
 63	    ) {
 64	      return true;
 65	    }
 66	    // Check pair_shot_generation_ids array
 67	    if (Array.isArray(orchDetails.pair_shot_generation_ids)) {
 68	      if (orchDetails.pair_shot_generation_ids.includes(generationId)) return true;
 69	    }
 70	  }
 71	
 72	  // Check full_orchestrator_payload
 73	  const fullPayload = params.full_orchestrator_payload as Record<string, unknown> | undefined;
 74	  if (fullPayload) {
 75	    if (fullPayload.based_on === generationId) return true;
 76	    if (fullPayload.source_generation_id === generationId) return true;
 77	    if (fullPayload.parent_generation_id === generationId) return true;
 78	  }
 79	
 80	  // Check individual_segment_params (used by individual_travel_segment)
 81	  const individualParams = params.individual_segment_params as Record<string, unknown> | undefined;
 82	  if (individualParams) {
 83	    if (individualParams.pair_shot_generation_id === generationId) return true;
 84	  }
 85	
 86	  return false;
 87	}
