 89	export function usePendingGenerationTasks(
 90	  generationId: string | null | undefined,
 91	  projectId: string | null | undefined
 92	): UsePendingGenerationTasksReturn {
 93	  // Query pending tasks for this project
 94	  const { data: pendingTasks, isLoading } = useQuery({
 95	    queryKey: [...taskQueryKeys.pendingGeneration(generationId!), projectId],
 96	    queryFn: async () => {
 97	      if (!generationId || !projectId) return [];
 98	
 99	      // Query tasks that are Queued or In Progress
100	      const { getSupabaseClient } = await import('@/integrations/supabase/client');
101	      const { data, error } = await getSupabaseClient().from('tasks')
102	        .select('id, status, task_type, params')
103	        .eq('project_id', projectId)
104	        .in('status', [TASK_STATUS.QUEUED, TASK_STATUS.IN_PROGRESS]);
105	
106	      if (error) {
107	        console.error('[usePendingGenerationTasks] Query error:', error);
108	        return [];
109	      }
110	
111	      // Filter to tasks that reference this generation
112	      const matchingTasks: PendingGenerationTask[] = (data || [])
113	        .filter(task => taskReferencesGeneration(task.params as Record<string, unknown> | null, generationId))
114	        .map(task => ({
115	          id: task.id,
116	          status: task.status,
117	          task_type: task.task_type,
118	        }));
119	
120	      return matchingTasks;
121	    },
122	    enabled: !!generationId && !!projectId,
123	    // Poll to catch status changes
124	    refetchInterval: 5000,
125	    // Mark as stale immediately so invalidations trigger refetch
126	    staleTime: 0,
127	    // Short cache time - don't keep stale data around
128	    gcTime: 10000,
129	    // Always refetch when window regains focus
130	    refetchOnWindowFocus: 'always',
131	  });
132	
133	  const result = useMemo(() => ({
134	    pendingCount: pendingTasks?.length || 0,
135	    pendingTasks: pendingTasks || [],
136	    isLoading,
137	  }), [pendingTasks, isLoading]);
138	
139	  return result;
140	}
